import{_ as h,o as t,c as i,a0 as a}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Thiết lập ABNERP","description":"","frontmatter":{"title":"Thiết lập ABNERP"},"headers":[],"relativePath":"setting-up.md","filePath":"setting-up.md"}'),l={name:"setting-up.md"};function c(o,n,e,r,u,g){return t(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="thiet-lap-abnerp" tabindex="-1">Thiết lập ABNERP <a class="header-anchor" href="#thiet-lap-abnerp" aria-label="Permalink to &quot;Thiết lập ABNERP&quot;">​</a></h1><h2 id="gioi-thieu-ve-thiet-lap-erp" tabindex="-1">Giới thiệu về thiết lập ERP <a class="header-anchor" href="#gioi-thieu-ve-thiet-lap-erp" aria-label="Permalink to &quot;Giới thiệu về thiết lập ERP&quot;">​</a></h2><p>Việc thiết lập một hệ thống ERP có thể là thách thức đối với nhiều doanh nghiệp. ABNERP được thiết kế để đơn giản hóa quy trình này, giúp bạn đi từ con số 0 đến một hệ thống vận hành hoàn chỉnh trong thời gian ngắn nhất.</p><p>Trước khi bắt đầu sử dụng ABNERP, bạn cần thiết lập một số danh mục dữ liệu nền tảng. Các danh mục này là những khối xây dựng cơ bản cho toàn bộ hệ thống.</p><h2 id="trang-web-abnerp" tabindex="-1">Trang web ABNERP <a class="header-anchor" href="#trang-web-abnerp" aria-label="Permalink to &quot;Trang web ABNERP&quot;">​</a></h2><p>Truy cập <a href="https://abnerp.vn" target="_blank" rel="noreferrer">https://abnerp.vn</a> để:</p><ul><li><strong>Dùng thử miễn phí</strong>: Đăng ký dùng thử ngay, không cần thẻ tín dụng</li><li><strong>Frappe Cloud</strong>: Triển khai trên nền tảng Frappe Cloud — dịch vụ quản lý hosting chuyên nghiệp</li><li><strong>Tải về</strong>: Tải mã nguồn để tự triển khai trên máy chủ riêng</li></ul><h2 id="cac-danh-muc-chinh" tabindex="-1">Các danh mục chính <a class="header-anchor" href="#cac-danh-muc-chinh" aria-label="Permalink to &quot;Các danh mục chính&quot;">​</a></h2><p>Sau khi đăng nhập vào hệ thống ABNERP, bạn cần thiết lập các danh mục dữ liệu cơ bản sau:</p><h3 id="_1-cong-ty" tabindex="-1">1. Công ty <a class="header-anchor" href="#_1-cong-ty" aria-label="Permalink to &quot;1. Công ty&quot;">​</a></h3><p>Công ty là thực thể pháp lý trung tâm của hệ thống. Mọi giao dịch và báo cáo đều gắn với một công ty cụ thể.</p><ul><li>Tạo công ty đầu tiên khi thiết lập tài khoản</li><li>Cấu hình thông tin: tên, mã số thuế, địa chỉ, logo</li><li>Thiết lập năm tài chính và tiền tệ mặc định</li></ul><p>Xem hướng dẫn chi tiết: <a href="/abnerp/company-setup.html">Thiết lập Công ty</a></p><h3 id="_2-mat-hang" tabindex="-1">2. Mặt hàng <a class="header-anchor" href="#_2-mat-hang" aria-label="Permalink to &quot;2. Mặt hàng&quot;">​</a></h3><p>Mặt hàng là sản phẩm hoặc dịch vụ mà doanh nghiệp của bạn mua, bán hoặc sản xuất.</p><ul><li>Tạo danh mục mặt hàng (nguyên vật liệu, bán thành phẩm, thành phẩm, dịch vụ)</li><li>Cấu hình đơn vị tính, giá bán, giá mua</li><li>Thiết lập nhóm mặt hàng và thuế suất</li></ul><p>Xem hướng dẫn chi tiết: <a href="/abnerp/item.html">Mặt hàng</a></p><h3 id="_3-khach-hang" tabindex="-1">3. Khách hàng <a class="header-anchor" href="#_3-khach-hang" aria-label="Permalink to &quot;3. Khách hàng&quot;">​</a></h3><p>Khách hàng là cá nhân hoặc tổ chức mua sản phẩm hoặc dịch vụ của bạn.</p><ul><li>Tạo danh sách khách hàng</li><li>Phân loại theo nhóm khách hàng</li><li>Lưu trữ địa chỉ, thông tin liên hệ, điều khoản thanh toán</li></ul><p>Xem hướng dẫn chi tiết: <a href="/abnerp/customer.html">Khách hàng</a></p><h3 id="_4-nha-cung-cap" tabindex="-1">4. Nhà cung cấp <a class="header-anchor" href="#_4-nha-cung-cap" aria-label="Permalink to &quot;4. Nhà cung cấp&quot;">​</a></h3><p>Nhà cung cấp là cá nhân hoặc tổ chức cung cấp sản phẩm hoặc dịch vụ cho doanh nghiệp bạn.</p><ul><li>Tạo danh sách nhà cung cấp</li><li>Lưu trữ thông tin hợp đồng, giá mua, điều khoản</li><li>Quản lý đánh giá nhà cung cấp</li></ul><p>Xem hướng dẫn chi tiết: <a href="/abnerp/supplier.html">Nhà cung cấp</a></p><h3 id="_5-so-đo-tai-khoan-danh-muc-ke-toan" tabindex="-1">5. Sơ đồ tài khoản (Danh mục kế toán) <a class="header-anchor" href="#_5-so-đo-tai-khoan-danh-muc-ke-toan" aria-label="Permalink to &quot;5. Sơ đồ tài khoản (Danh mục kế toán)&quot;">​</a></h3><p>Sơ đồ tài khoản là cấu trúc tài khoản kế toán của doanh nghiệp.</p><ul><li>ABNERP tự động tạo sơ đồ tài khoản mặc định dựa trên quốc gia</li><li>Bạn có thể tùy chỉnh thêm các tài khoản đặc thù</li><li>Cấu hình thuế, loại tài khoản</li></ul><h3 id="_6-cong-cu-nhap-du-lieu" tabindex="-1">6. Công cụ nhập dữ liệu <a class="header-anchor" href="#_6-cong-cu-nhap-du-lieu" aria-label="Permalink to &quot;6. Công cụ nhập dữ liệu&quot;">​</a></h3><p>ABNERP cung cấp công cụ nhập dữ liệu hàng loạt (Data Import) để bạn dễ dàng chuyển đổi dữ liệu từ hệ thống cũ.</p><ul><li>Hỗ trợ nhập từ file CSV hoặc Excel</li><li>Tự động ánh xạ trường dữ liệu</li><li>Kiểm tra và xác thực dữ liệu trước khi nhập</li></ul><h3 id="_7-so-du-đau-ky" tabindex="-1">7. Số dư đầu kỳ <a class="header-anchor" href="#_7-so-du-đau-ky" aria-label="Permalink to &quot;7. Số dư đầu kỳ&quot;">​</a></h3><p>Thiết lập số dư đầu kỳ cho các tài khoản kế toán và tồn kho.</p><ul><li>Nhập số dư tài khoản (công nợ, tiền mặt, ngân hàng, v.v.)</li><li>Nhập số dư tồn kho đầu kỳ</li><li>Nhập số dư công nợ phải thu, phải trả</li></ul><h2 id="video-huong-dan" tabindex="-1">Video hướng dẫn <a class="header-anchor" href="#video-huong-dan" aria-label="Permalink to &quot;Video hướng dẫn&quot;">​</a></h2><p>Để được hướng dẫn trực quan, bạn có thể xem các video hướng dẫn thiết lập ABNERP trên kênh YouTube chính thức. Các video bao gồm:</p><ul><li><strong>Thiết lập cơ bản</strong>: Tạo công ty, thiết lập danh mục</li><li><strong>Quản lý kho hàng</strong>: Nhập xuất tồn, kiểm kê</li><li><strong>Kế toán</strong>: Hạch toán, báo cáo thuế</li><li><strong>Bán hàng</strong>: Quy trình từ báo giá đến xuất hóa đơn</li><li><strong>Nhân sự</strong>: Quản lý chấm công và bảng lương</li></ul>',37)])])}const s=h(l,[["render",c]]);export{d as __pageData,s as default};
